SELECT t.ticker, t.time FROM `tav2_bq.ticker` AS t WHERE (t.time >= '2020-01-01' AND t.time <= '2026-04-03') AND ((t.Volume_3M_P50*t.Price/ NULLIF(t.Inflation_7, 0))>1000000000.0) AND (t.Risk_Rating <= 6) AND (t.Close > 1.12*t.Volume_Max1Y_High) AND (t.Close_T1W < 1.07*t.Volume_Max1Y_High) AND (t.Volume > 0.95*t.Volume_3M_P50) AND (t.PE >1.6) AND (t.PE < 19.0) AND (t.PB<3.1) AND (t.PB > 0.4) AND (((t.NP_P0 > 1.0*t.NP_P1) AND (t.PCF < 19.8) AND (t.ROE_Min3Y > 0.03)) OR ((((t.NP_P0 - t.NP_P4)/ABS(t.NP_P4) > 0.70)) AND (t.PCF < 15.8))) AND (t.PCF > 2.4000000000000004) AND (t.ID_Current-t.Volume_Max1Y_ID<=205.0) AND (t.Volume_Max1Y_High/ NULLIF(t.LO_3M_T1, 0) < 1.4500000000000002) AND (t.FSCORE > 3.0) ORDER BY t.ticker, t.time